    var psProductListA = 0;
    window.addEventListener('scroll', function () {
        //获取需要曝光的元素
        var obj = $("#ps-product-list-id").find(".mr-products-solutions-text-img-tit")[0];
        //取曝光元素的top
        let top = obj.getBoundingClientRect().top;
        //取页面滚动条实时的滚动高度
        let scrollBarTop = document.body.scrollTop || document.documentElement.scrollTop;
        //需要曝光的元素在页面的高度=top+滚动条实时高度
        let domX = top + scrollBarTop;
        //滚动条实时高度+浏览器窗口高度 >= 需要曝光的元素在页面的高度
        if (scrollBarTop + window.screen.height >= domX && psProductListA == 0) {
            BuriedPointPsProductListListExposure($("#ps-product-list-id").find(".mr-products-solutions-text-img-tit")[0].textContent);
            psProductListA = 1;
        }
    });

    function BuriedPointPsProductListListExposure(moduleName) {
