body.script:
piAId = '75312';
piCId = '173744';
piHostname = 'www2.mindray.com';

(function () {
  function async_load() {
    var s = document.createElement('script'); s.type = 'text/javascript';
    s.src = ('https:' == document.location.protocol ? 'https://' : 'http://') + piHostname + '/pd.js';
    var c = document.getElementsByTagName('script')[0]; c.parentNode.insertBefore(s, c);
  }

  function getOneTrustCookies() {
    var OptanonConsent = document.cookie && document.cookie.split('OptanonConsent=') || '';
    if (!OptanonConsent || OptanonConsent.length < 2) {
      return false;
    }
    var splitStr = OptanonConsent[1].split(';')[0];
    if (!splitStr) {
      return false;
    }
    var geolocation = splitStr.split('groups=');
    if (geolocation && geolocation.length > 1) {
      return decodeURIComponent(geolocation[1]).indexOf('C0002:1') > -1;
    } else {
      return false;
    }
    return false;
  }

  document.addEventListener('DOMContentLoaded', function () {
    var isShowCookiesTips = getOneTrustCookies();
    if (isShowCookiesTips) {
      async_load()
    }

    document.addEventListener('click', function (e) {
      if (e.target.matches('#onetrust-accept-btn-handler, #accept-recommended-btn-handler')) {
        async_load()
      }
    });

    document.addEventListener('click', function (e) {
      if (e.target.closest('#onetrust-consent-sdk .onetrust-close-btn-handler')) {
        var checkbox = document.querySelector('#onetrust-consent-sdk #ot-group-id-C0002');
        if (checkbox && checkbox.checked) {
          async_load()
        }
      }
    });
  });
})();

    $(function () {
