    function getScrollPercentage() {
        const scrollTop = document.documentElement.scrollTop || document.body.scrollTop;
        const scrollHeight = document.documentElement.scrollHeight || document.body.scrollHeight;
        const clientHeight = document.documentElement.clientHeight || window.innerHeight;
        const percent = (scrollTop / (scrollHeight - clientHeight)) * 100;
        return percent.toFixed(2);
    }

    var a = 0;
    var b = 0;
    var c = 0;
    var d = 0;

    var $pageGroup;
    var $pageUrl = window.location.href;
    var $scrollPercentage;

    if ($pageUrl.indexOf("www.mindray.com/en/about/") != -1) {
        $pageGroup = "about";
    } else if ($pageUrl.indexOf("www.mindray.com/en/careers/") != -1) {
        $pageGroup = "careers";
    } else if ($pageUrl.indexOf("www.mindray.com/en/covid-19-response/") != -1) {
        $pageGroup = "covid-19-response";
    } else if ($pageUrl.indexOf("www.mindray.com/en/innovation/") != -1) {
        $pageGroup = "innovation";
    } else if ($pageUrl.indexOf("www.mindray.com/en/services/") != -1) {
        $pageGroup = "services";
    } else {
        $pageGroup = "other";
    }

    window.addEventListener('scroll', function () {
        const scrollPercent = getScrollPercentage();
        // 触发自定义事件
        if (scrollPercent >= 25 && a == 0) {
            a = 1;
            $scrollPercentage = scrollPercent;
            pageBrowseDepthBuriedPoint();
        } else if (scrollPercent >= 50 && b == 0) {
            b = 1;
            $scrollPercentage = scrollPercent;
            pageBrowseDepthBuriedPoint();
        } else if (scrollPercent >= 75 && c == 0) {
            c = 1;
            $scrollPercentage = scrollPercent;
            pageBrowseDepthBuriedPoint();
        } else if (scrollPercent >= 100 && d == 0) {
            d = 1;
            $scrollPercentage = scrollPercent;
            pageBrowseDepthBuriedPoint();
        }
    });

    function pageBrowseDepthBuriedPoint() {
        window.dataLayer.push({"event_parameters": "null"});
        window.dataLayer.push({
            "event": "ga4Event",
            "event_name": "scroll",
            "event_parameters": {
                "page_group": $pageGroup,
                "page_url": $pageUrl,
                "percent_scrolled": $scrollPercentage
            }
        });
    }
